def solve():
    n, k = map(int, input().split())
    if k <= n:
        if k % 2 == 1:
            print(k)
        else:
            print(k - 1)
    else:
        if k % 2 == 0:
            print(k - 2 * (k - n))
        else:
            print(2 * (k - n))




def main():
    solve()


if __name__ == "__main__":
    main()
